using UnityEditor;
using UnityEngine;
using System.Collections.Generic;

public class ShaderUpgrader
{
    public static string Upgrade()
    {
        string[] guids = AssetDatabase.FindAssets("t:Material");
        int upgradedCount = 0;
        Shader urpLit = Shader.Find("Universal Render Pipeline/Lit");
        if (urpLit == null)
        {
            return "Universal Render Pipeline/Lit shader not found!";
        }

        foreach (string guid in guids)
        {
            string path = AssetDatabase.GUIDToAssetPath(guid);
            Material mat = AssetDatabase.LoadAssetAtPath<Material>(path);
            if (mat != null && (mat.shader.name == "Standard" || mat.shader.name == "Standard (Specular setup)"))
            {
                mat.shader = urpLit;
                EditorUtility.SetDirty(mat);
                upgradedCount++;
            }
        }
        AssetDatabase.SaveAssets();
        return $"Successfully upgraded {upgradedCount} materials to URP Lit.";
    }
}
